import React, { useState } from "react";
import "./App.css";

function App() {
  const [grammar, setGrammar] = useState(`S -> aSa | bSb | a | b`);
  const [input, setInput] = useState("aba");
  const [startSymbol, setStartSymbol] = useState("S");

  const [leftSteps, setLeftSteps] = useState([]);
  const [rightSteps, setRightSteps] = useState([]);
  const [parseTree, setParseTree] = useState(null);

  const [currentStep, setCurrentStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleGenerate = async () => {
    setLoading(true);
    setError("");
    setCurrentStep(0);

    try {
      const res = await fetch("http://localhost:5001/api/derive", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          grammar,
          input,
          startSymbol,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || "Error generating");
      }

      setLeftSteps(data.leftDerivation || []);
      setRightSteps(data.rightDerivation || []);
      setParseTree(data.parseTree || null);
    } catch (err) {
      setError("Cannot reach backend. Run: cd backend && node server.js");
    }

    setLoading(false);
  };

  return (
    <div className="app">
      <h1>CFG Derivation & Parse Tree Generator</h1>

      {/* INPUT */}
      <div className="card">
        <h3>Grammar</h3>
        <textarea
          value={grammar}
          onChange={(e) => setGrammar(e.target.value)}
        />

        <div className="inputs">
          <input
            value={startSymbol}
            onChange={(e) => setStartSymbol(e.target.value)}
            placeholder="Start Symbol"
          />
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Input String"
          />
        </div>

        <button onClick={handleGenerate}>
          {loading ? "Generating..." : "Generate"}
        </button>
      </div>

      {error && <div className="error">{error}</div>}

      {/* LEFT DERIVATION STEP MODE */}
      {leftSteps.length > 0 && (
        <div className="card">
          <h3>Leftmost Derivation</h3>

          <div className="step">
            <span className="step-index">{currentStep}</span>
            <span className="step-value">
              {leftSteps[currentStep]}
            </span>
          </div>

          <div className="controls">
            <button
              disabled={currentStep === 0}
              onClick={() =>
                setCurrentStep((prev) => Math.max(prev - 1, 0))
              }
            >
              ⬅ Prev
            </button>

            <button
              disabled={currentStep === leftSteps.length - 1}
              onClick={() =>
                setCurrentStep((prev) =>
                  Math.min(prev + 1, leftSteps.length - 1)
                )
              }
            >
              Next ➡
            </button>
          </div>
        </div>
      )}

      {/* RIGHT DERIVATION STEP MODE */}
      {rightSteps.length > 0 && (
        <div className="card">
          <h3>Rightmost Derivation</h3>

          <div className="step">
            <span className="step-index">{currentStep}</span>
            <span className="step-value">
              {rightSteps[currentStep]}
            </span>
          </div>
        </div>
      )}

      {/* PARSE TREE */}
      {parseTree && (
        <div className="card">
          <h3>Parse Tree</h3>
          <pre>{JSON.stringify(parseTree, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

export default App;
